const llmRaw = $input.item.json.choices?.[0]?.message?.content || '';
const grund = llmRaw.replace(/<think>[\s\S]*?</think>/gi, '').trim() || 'mich die Kombination aus KI und Automatisierung in Ihrem Unternehmen überzeugt';

const job = $('DB: Jobs mit Email holen').item.json;
const firma = job.company_name || 'Ihr Unternehmen';
const ort = job.location || 'Berlin';
const stelle = job.job_title || 'die ausgeschriebene Stelle';

const heute = new Date().toLocaleDateString('de-DE', { day: '2-digit', month: 'long', year: 'numeric' });

const body = `Kirill Brüggemann · Berlin
ogi-ogi@mail.de · github.com/KiBrueg · linkedin.com/in/ki-brueg-2520033bb

Berlin, ${heute}

${firma}
${ort}

Betreff: Bewerbung als ${stelle} (m/w/d)

Sehr geehrte Damen und Herren,

ich bin Automation Engineer aus Berlin mit Schwerpunkt auf KI-gestützten Systemen, LLM-Integration und Backend-Entwicklung. Ich bewerbe mich bei ${firma}, weil ${grund}. Das Arbeitsformat ist für mich flexibel — Praktikum, Teilzeit, Vollzeit oder freiberuflich; entscheidend ist das Problem, das wir gemeinsam lösen.

Was ich mitbringe: Ich baue produktionsreife Systeme in Python, die wirklich laufen. Mein Referenzprojekt JobRadar ist eine vollautomatisierte Multi-Source-Pipeline mit LLM-Parser, PostgreSQL-Backend, HMAC-Webhook-Auth und Prompt Injection Detection — deployed auf eigenem VPS mit Docker. Daneben habe ich einen Crypto Intel Agent mit Multi-Agenten-Architektur (Council of Advisors), Vektorsuche via pgvector und vollständiger pytest-Test-Suite entwickelt. LLM-APIs (Claude, OpenAI, open-source über OpenRouter), REST-Integrationen, n8n-Workflows, Telegram-Bots — alles aus eigener Initiative, ohne Team, ohne Deadline-Druck von außen.

Ich bin Berliner, spreche Deutsch auf Verhandlungsniveau (C1), Englisch (B2) und Russisch (Muttersprache). Remote bevorzugt, Hybrid oder vor Ort nach Absprache möglich. Verfügbar kurzfristig.

Wenn Sie ein konkretes Problem haben, das Automatisierung, KI oder Backend-Entwicklung lösen kann — ich höre gerne zu.

Mit freundlichen Grüßen,
Kirill Brüggemann

---
📄 Lebenslauf: https://drive.google.com/file/d/1HwbI0zcSySikQdV2yEJuaoeU-hyNaDVy/view
📊 Portfolio (JobRadar): https://drive.google.com/file/d/1G2uANtdZywakvzyt4JJyA73tI4ilzO5W/view
🔗 GitHub: https://github.com/KiBrueg
🔗 LinkedIn: https://linkedin.com/in/ki-brueg-2520033bb`;

return {
  job_id: job.id,
  contact_email: job.contact_email,
  subject: `Bewerbung als ${stelle} (m/w/d) — Kirill Brüggemann`,
  body,
  firma,
  stelle
};

